const data = $input.first().json.body || $input.first().json;

if (!data.job_id) {
  return [{ json: { skip: true, reason: 'Callback missing job_id' } }];
}

if (data.status !== 'completed') {
  return [{ json: { skip: true, reason: `Job status is ${data.status}` } }];
}

// Support audio_uri (new) and gcs_uri (backward-compat)
const rawUri = data.audio_uri || data.gcs_uri || '';

if (!rawUri) {
  return [{ json: { skip: true, reason: 'No audio_uri in callback payload' } }];
}

// Resolve to public HTTP URL based on URI scheme
let audioUrl = '';

if (rawUri.startsWith('gs://')) {
  const parts = rawUri.replace('gs://', '').split('/');
  const bucket = parts.shift();
  const objectPath = parts.join('/');
  audioUrl = `https://storage.googleapis.com/${bucket}/${objectPath}`;

} else if (rawUri.startsWith('s3://')) {
  const withoutScheme = rawUri.replace('s3://', '');
  const slashIdx = withoutScheme.indexOf('/');
  const bucket = withoutScheme.substring(0, slashIdx);
  const key = withoutScheme.substring(slashIdx + 1);
  const region = $env.AWS_REGION || 'us-east-1';
  audioUrl = `https://${bucket}.s3.${region}.amazonaws.com/${key}`;

} else if (rawUri.startsWith('local://')) {
  const jobFile = rawUri.replace('local://', '');
  const jobId = jobFile.replace('.mp3', '');
  const ttsPublicUrl = $env.TTS_PUBLIC_URL || $env.TTS_SERVICE_URL || 'http://localhost:8020';
  audioUrl = `${ttsPublicUrl}/tts/download/${jobId}`;

} else {
  return [{ json: { skip: true, reason: `Unknown audio URI scheme: ${rawUri}` } }];
}

// Extract postId from job_id
let postId = '';
let siteSlug = '';

if (data.job_id.includes('-pid-')) {
  const parts = data.job_id.split('-pid-');
  siteSlug = parts[0];
  postId = parts[1].split('-')[0];
} else {
  const parts = data.job_id.split('-');
  const postIdIndex = parts.findIndex(part => part.length === 24 && /^[0-9a-fA-F]+$/.test(part));
  if (postIdIndex !== -1) {
    postId = parts[postIdIndex];
    siteSlug = parts.slice(0, postIdIndex).join('-');
  }
}

if (!postId || postId.length !== 24) {
  return [{ json: { skip: true, reason: `Could not extract valid post ID from: ${data.job_id}` } }];
}

return [{
  json: {
    skip: false,
    jobId: data.job_id,
    postId,
    siteSlug,
    audioUrl,
    audioUri: rawUri
  }
}];

// Use siteSlug from the callback payload (set by Check Status & Parse Job ID node)
const slug = $json.siteSlug;
const adminApiKey = slug === 'site1'
  ? $env.GHOST_SITE1_ADMIN_API_KEY
  : slug === 'site2'
  ? $env.GHOST_SITE2_ADMIN_API_KEY
  : null;

if (!adminApiKey) {
  throw new Error(`No admin API key configured for site slug: "${slug}". Expected 'site1' or 'site2'.`);
}

// Get the Ghost URL based on site slug
const ghostUrl = slug === 'site1' 
  ? $env.GHOST_SITE1_URL 
  : slug === 'site2' 
  ? $env.GHOST_SITE2_URL 
  : null;

if (!ghostUrl) {
  throw new Error(`No Ghost URL configured for site slug: "${slug}". Expected GHOST_SITE1_URL or GHOST_SITE2_URL.`);
}

const [keyId, secret] = adminApiKey.split(':');

return [{
  json: {
    ...$json,
    ghostKeyId: keyId,
    ghostSecret: secret,
    ghostUrl: ghostUrl
  }
}];

const postData = $input.first().json;
const post = postData.posts?.[0];

if (!post) {
    throw new Error('Ghost API did not return a post');
}

if (post.status !== 'published') {
    return [{ json: { skipUpdate: true, reason: `Post is in ${post.status} status, skipping embed` } }];
}

const parsed = $('Check Status & Parse Job ID').first().json;
let html = post.html || '';

// Sovereign Dashboard Aesthetic: Brutalist Utility
const audioWidget = `
<!--kg-card-begin: html-->
<div id="gn-audio-embed" style="margin: 40px 0; border-top: 2px solid #000; border-bottom: 1px solid #e1e1e1; padding: 16px 0; font-family: Inter, system-ui, -apple-system, sans-serif; background: #fff;">
    <div style="display: flex; align-items: center; justify-content: space-between; gap: 20px;">
        <div style="display: flex; align-items: center; gap: 14px; flex-grow: 1;">
            <button onclick="const a = this.closest('#gn-audio-embed').querySelector('audio'); if(a.paused){a.play(); this.innerHTML='&#10074;&#10074;';}else{a.pause(); this.innerHTML='&#9654;';}" 
                    style="width: 44px; height: 44px; border-radius: 50%; border: none; background: #000; color: #fff; cursor: pointer; display: flex; align-items: center; justify-content: center; font-size: 16px; flex-shrink: 0; transition: transform 0.1s;">
                &#9654;
            </button>
            <div style="display: flex; flex-direction: column; gap: 2px;">
                <span style="font-weight: 800; font-size: 13px; text-transform: uppercase; letter-spacing: 0.02em; color: #000;">Listen to article</span>
                <span class="gn-audio-time" style="font-size: 11px; color: #737373; font-family: monospace;">0:00 / 0:00</span>
            </div>
            <div style="flex-grow: 1; height: 4px; background: #f0f0f0; position: relative; border-radius: 2px; overflow: hidden; margin: 0 10px; max-width: 300px;">
                <div class="gn-audio-progress" style="position: absolute; left: 0; top: 0; height: 100%; width: 0%; background: #000;"></div>
            </div>
        </div>
        <div style="display: flex; align-items: center; gap: 6px;">
            <span style="font-size: 10px; font-weight: 700; color: #a3a3a3; text-transform: uppercase;">Speed</span>
            <button onclick="const a = this.closest('#gn-audio-embed').querySelector('audio'); const rates = [1, 1.25, 1.5, 2]; let idx = rates.indexOf(a.playbackRate); const next = rates[(idx + 1) % rates.length]; a.playbackRate = next; this.innerText = next + 'x'" 
                    style="background: #fff; border: 1.5px solid #000; border-radius: 4px; padding: 2px 8px; font-size: 11px; cursor: pointer; color: #000; font-weight: 800; min-width: 42px;">
                1x
            </button>
        </div>
    </div>
    <audio preload="metadata" style="display:none;" ontimeupdate="const p = (this.currentTime / this.duration) * 100; const embed = this.closest('#gn-audio-embed'); embed.querySelector('.gn-audio-progress').style.width = p + '%'; const m = Math.floor(this.currentTime / 60); const s = Math.floor(this.currentTime % 60); const dm = Math.floor(this.duration / 60); const ds = Math.floor(this.duration % 60); if(!isNaN(dm)) embed.querySelector('.gn-audio-time').innerText = m + ':' + (s<10?'0':'') + s + ' / ' + dm + ':' + (ds<10?'0':'') + ds;" onended="this.closest('#gn-audio-embed').querySelector('button').innerHTML='&#9654;';">
        <source src="${parsed.audioUrl}" type="audio/mpeg">
    </audio>
</div>
<!--kg-card-end: html-->
`;

let newHtml = '';
const embedRegex = /<!--kg-card-begin: html-->[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<!--kg-card-end: html-->|<figure[^>]*>[\s\S]*?id=["']gn-audio-embed["'][\s\S]*?<\/figure>|<div[^>]*id=["']gn-audio-embed["'][^>]*>[\s\S]*?<\/div>/i;

if (embedRegex.test(html)) {
    newHtml = html.replace(embedRegex, audioWidget.trim());
} else {
    newHtml = audioWidget + html;
}

const authData = $('Create Ghost JWT').first().json;

return [{
  json: {
    skipUpdate: false,
    postId: post.id,
    updatedAt: post.updated_at,
    siteSlug: parsed.siteSlug,
    ghostUrl: authData.ghostUrl,
    ghostJwtToken: authData.ghostJwtToken,
    newHtml
  }
}];

const crypto = require('crypto');

const keyId = $json.ghostKeyId;
const secret = $json.ghostSecret;
const now = Math.floor(Date.now() / 1000);

// Ghost Admin API JWT Headers
const header = {
    alg: 'HS256',
    kid: keyId,
    typ: 'JWT'
};

// Ghost Admin API JWT Payload
const payload = {
    iat: now,
    exp: now + 300, // 5 minutes max
    aud: '/admin/'
};

// Helper: Base64URL encode without padding
function base64Url(str) {
    return Buffer.from(str)
        .toString('base64')
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=/g, '');
}

const encodedHeader = base64Url(JSON.stringify(header));
const encodedPayload = base64Url(JSON.stringify(payload));
const signingInput = `${encodedHeader}.${encodedPayload}`;

// CRITICAL: Decode the hex secret into bytes before signing
const keyBytes = Buffer.from(secret, 'hex');

// Sign with HMAC-SHA256
const signature = crypto
    .createHmac('sha256', keyBytes)
    .update(signingInput)
    .digest('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');

const token = `${signingInput}.${signature}`;

return [{
    json: {
        ...$json,
        ghostJwtToken: token
    }
}];
